"""Replicate the numpy.typing __init__.py pattern minimally."""

from other import ArrayLike, DTypeLike, NBitBase, NDArray  # binds all 4 in globals()

__all__ = ["ArrayLike", "DTypeLike", "NBitBase", "NDArray"]

__DIR = __all__ + [k for k in globals() if k.startswith("__") and k.endswith("__")]
__DIR_SET = frozenset(__DIR)


def __dir__() -> list[str]:
    return __DIR


def __getattr__(name: str) -> object:
    print(f"  [__getattr__ called for {name!r}]")
    if name == "NBitBase":
        import warnings

        warnings.warn(
            "`NBitBase` is deprecated (deprecated in NumPy 2.3)",
            DeprecationWarning,
            stacklevel=2,
        )
        return NBitBase

    if name in __DIR_SET:
        return globals()[name]

    raise AttributeError(f"module {__name__!r} has no attribute {name!r}")

